import { describe, expect, it, vi } from "vitest";
import { createStudioSession } from "./createStudioSession.js";
vi.mock("../activeStudioSession.js", () => ({
    writeActiveStudioSession: vi.fn(),
}));
vi.mock("../agentSessionChannel.js", () => ({
    createAgentSession: vi.fn().mockResolvedValue({ ok: true }),
}));
vi.mock("../browser.js", () => ({
    openChromelessWindow: vi.fn().mockReturnValue(4242),
}));
const SESSION_ID = "11111111-1111-4111-8111-111111111111";
const SERVICE_URL = "https://test.invalid";
const API_KEY = "key-test";
describe("createStudioSession", () => {
    it("creates an agent session", async () => {
        const { createAgentSession } = await import("../agentSessionChannel.js");
        await createStudioSession({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(createAgentSession).toHaveBeenCalledWith(expect.objectContaining({ sessionId: SESSION_ID, apiKey: API_KEY }));
    });
    it("writes active session file with the spawned window pid", async () => {
        const { writeActiveStudioSession } = await import("../activeStudioSession.js");
        await createStudioSession({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(writeActiveStudioSession).toHaveBeenCalledWith({
            sessionId: SESSION_ID,
            serviceUrl: SERVICE_URL,
            windowPid: 4242,
        });
    });
    it("opens chromeless window with session param", async () => {
        const { openChromelessWindow } = await import("../browser.js");
        await createStudioSession({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            initialPath: "/studio/experiments",
        });
        expect(openChromelessWindow).toHaveBeenCalledWith(expect.stringContaining(`session=${SESSION_ID}`));
        expect(openChromelessWindow).toHaveBeenCalledWith(expect.stringContaining("/studio/experiments"));
    });
    it("returns sessionId and serviceUrl", async () => {
        const result = await createStudioSession({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(result.sessionId).toBe(SESSION_ID);
        expect(result.serviceUrl).toBe(SERVICE_URL);
    });
});
